const topics = [
  'AI tools that boost productivity',
  'Lessons learned from automating workflows',
  'The future of remote work and AI',
  'Personal branding tips for professionals',
  'Cybersecurity habits everyone should build',
  'How no-code tools are changing tech careers',
  'Mistakes people make early in their career'
];

const now = new Date();
const start = new Date(now.getFullYear(), 0, 0);
const diff = now - start;
const oneDay = 1000 * 60 * 60 * 24;
const dayOfYear = Math.floor(diff / oneDay);

const todayTopic = topics[dayOfYear % topics.length];

return [{
  json: {
    topic: todayTopic,
    date: now.toISOString().split('T')[0]
  }
}];

let parsed;
try {
  const raw = String($json.output || '').replace(/```json\n?|```/g, '').trim();
  parsed = JSON.parse(raw);
} catch (e) {
  parsed = {
    post_text: String($json.output || '').trim(),
    image_prompt: 'professional minimalist business illustration'
  };
}

const prompt = (parsed && parsed.image_prompt) || 'professional minimalist business illustration';
const encodedPrompt = encodeURIComponent(prompt + ', high quality, professional, clean, no text, no watermark');
const imageUrl = `https://image.pollinations.ai/prompt/${encodedPrompt}?width=1024&height=1024&nologo=true`;

return [{
  json: {
    post_text: parsed.post_text,
    image_prompt: parsed.image_prompt,
    image_url: imageUrl,
    topic: $('Pick Today\'s Topic').item.json.topic,
    date: $('Pick Today\'s Topic').item.json.date
  }
}];
